 1→import React, { useEffect, useState } from 'react';
 2→
 3→interface ScoreRingProps {
 4→  score: number;
 5→  size?: number;
 6→  strokeWidth?: number;
 7→  noAnimation?: boolean;
 8→}
 9→
10→const ScoreRing: React.FC<ScoreRingProps> = ({ score, size = 120, strokeWidth = 8, noAnimation = false }) => {
11→  const [animatedScore, setAnimatedScore] = useState(noAnimation ? score : 0);
12→  const radius = (size - strokeWidth) / 2;
13→  const circumference = radius * 2 * Math.PI;
14→  const offset = circumference - (animatedScore / 100) * circumference;
15→
16→  useEffect(() => {
17→    if (noAnimation) {
18→      setAnimatedScore(score);
19→      return;
20→    }
21→    const timer = setTimeout(() => {
22→      setAnimatedScore(score);
23→    }, 100);
24→    return () => clearTimeout(timer);
25→  }, [score, noAnimation]);
26→
27→  const getColor = (s: number) => {
28→    if (s >= 80) return '#a855f7'; // Purple
29→    if (s >= 60) return '#c084fc'; // Light Purple
30→    if (s >= 40) return '#7c3aed'; // Violet
31→    return '#ef4444'; // Red
32→  };
33→
34→  const color = getColor(animatedScore);
35→
36→  return (
37→    <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
38→      <svg width={size} height={size} className="transform -rotate-90">
39→        {/* Background Ring */}
40→        <circle
41→          cx={size / 2}
42→          cy={size / 2}
43→          r={radius}
44→          stroke="#ffffff"
45→          strokeOpacity="0.08"
46→          strokeWidth={strokeWidth}
47→          fill="transparent"
48→        />
49→        {/* Progress Ring */}
50→        <circle
51→          cx={size / 2}
52→          cy={size / 2}
53→          r={radius}
54→          stroke={color}
55→          strokeWidth={strokeWidth}
56→          fill="transparent"
57→          strokeDasharray={circumference}
58→          strokeDashoffset={offset}
59→          strokeLinecap="round"
60→          className={noAnimation ? '' : "transition-all duration-1000 ease-out"}
61→        />
62→      </svg>
63→      <div className="absolute flex flex-col items-center">
64→        <span className="text-3xl font-bold font-sans" style={{ color }}>{animatedScore}</span>
65→        <span className="text-xs text-gray-500 uppercase tracking-wider font-medium">AEO Score</span>
66→      </div>
67→    </div>
68→  );
69→};
70→
71→export default ScoreRing;

 1→// components/ui/Button.tsx
 2→// Système de boutons unifié — Primary inspiré Vercel (blanc sur sombre).
 3→
 4→import React from 'react';
 5→
 6→interface ButtonProps {
 7→  children: React.ReactNode;
 8→  variant?: 'primary' | 'secondary' | 'ghost' | 'danger';
 9→  size?: 'sm' | 'md' | 'lg';
10→  icon?: React.ElementType;
11→  iconPosition?: 'left' | 'right';
12→  loading?: boolean;
13→  disabled?: boolean;
14→  onClick?: () => void;
15→  className?: string;
16→  type?: 'button' | 'submit' | 'reset';
17→}
18→
19→const VARIANT_STYLES = {
20→  primary: 'bg-white text-black font-medium hover:bg-gray-200 active:bg-gray-300 disabled:opacity-50',
21→  secondary: 'bg-transparent text-[var(--text-secondary)] border border-white/[0.06] hover:border-white/[0.1] hover:text-[var(--text-primary)]',
22→  ghost: 'bg-transparent text-[var(--text-secondary)] hover:bg-white/[0.06] hover:text-[var(--text-primary)]',
23→  danger: 'bg-transparent text-[var(--error)] border border-red-500/20 hover:bg-[var(--error-subtle)]',
24→};
25→
26→const SIZE_STYLES = {
27→  sm: 'text-[13px] px-3 py-1.5 rounded-lg gap-1.5',
28→  md: 'text-sm px-4 py-2 rounded-lg gap-2',
29→  lg: 'text-sm px-5 py-2.5 rounded-lg gap-2',
30→};
31→
32→const Spinner = () => (
33→  <svg className="animate-spin w-4 h-4" viewBox="0 0 24 24" fill="none">
34→    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="3" />
35→    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
36→  </svg>
37→);
38→
39→export default function Button({
40→  children,
41→  variant = 'primary',
42→  size = 'md',
43→  icon: Icon,
44→  iconPosition = 'left',
45→  loading = false,
46→  disabled = false,
47→  onClick,
48→  className = '',
49→  type = 'button',
50→}: ButtonProps) {
51→  const isDisabled = disabled || loading;
52→
53→  return (
54→    <button
55→      type={type}
56→      onClick={onClick}
57→      disabled={isDisabled}
58→      className={`
59→        inline-flex items-center justify-center font-medium
60→        transition-all duration-150 press-effect
61→        ${isDisabled ? 'cursor-not-allowed' : 'cursor-pointer'}
62→        ${VARIANT_STYLES[variant]}
63→        ${SIZE_STYLES[size]}
64→        ${className}
65→      `.trim()}
66→    >
67→      {loading && <Spinner />}
68→      {!loading && Icon && iconPosition === 'left' && <Icon className="w-4 h-4" />}
69→      <span className={loading ? 'opacity-70' : ''}>{children}</span>
70→      {!loading && Icon && iconPosition === 'right' && <Icon className="w-4 h-4" />}
71→    </button>
72→  );
73→}
